;

;-----------------------------------------------------
;	LABELS USED WHICH DIFFER FROM FIG-FORTH PUBLISHED
;	8080 LISTING 1.0:
;
;	REL 1.1		REL 1.0
;	-------		-------
;	ANDD		AND
;	CSPP		CSP
;	ELSEE		ELSE
;	ENDD		END
;	ENDIFF		ENDIF
;	ERASEE		ERASE
;	IDO		I
;	IFF		IF
;	INN		IN
;	MODD		MOD
;	ORR		OR
;	OUTT		OUT
;	RR		R
;	RPP		RP
;	SUBB		SUB
;	XORR		XOR
;
;	SEE ALSO:
;		RELEASE & VERSION NUMBERS
;		ASCII CHARACTER EQUATES
;		MEMORY ALLOCATION
;		DISK INTERFACE
;		CONSOLE & PRINTER INTERFACE
;
; PAGE
;
;----------------------------------------------------------
;
;	RELEASE & VERSION NUMBERS
;
FIGREL:	EQU 1	; FIG RELEASE #
FIGREV:	EQU 1	; FIG REVISION #
USRVER:	EQU 0	; USER VERSION #
;
;	ASCII CHARACTERS USED
;
ABL:	EQU 20H	; SPACE
ACR:	EQU 0DH	; CARRIAGE RETURN
ADOT:	EQU 02EH	; PERIOD
BELL:	EQU 07H	; (^G)
BSIN:	EQU 7FH	; INPUT BACKSPACE CHR = RUBOUT
BSOUT:	EQU 08H	; OUTPUT BACKSPACE (^H)
DLE:	EQU 10H	; (^P)
LF:	EQU 0AH	; LINE FEED
FF:	EQU 0CH	; FORM FEED (^L)
;
;	MEMORY ALLOCATION
;
EM:	EQU	0xBF00	; TOP OF MEMORY + 1 = LIMIT
KBBUF:	EQU	128	; DATA BYTES PER DISK BUFFER (kept for B/BUF)
US:	EQU	40H	; USER VARIABLES SPACE
RTS:	EQU	0A0H	; RETURN STACK & TERM BUFF SPACE
;
INITR0:	EQU	EM-US		; (R0)
INITS0:	EQU	INITR0-RTS	; (S0)
; PAGE
;
;-------------------------------------------------------
;

	INCLUDE "../../src/include/syscall.asm"

	ORG  0

	; Entry point — jump over the header
	JP   forth_entry

	; Header pad: 13 bytes of zeros (offsets 3-15 reserved)
	DEFS 13, 0

; ============================================================
; forth_entry - NostOS entry point (at 0x0810)
; ============================================================
forth_entry:
	JP   ORIG

ORIG:	NOP
	JP   CLD	; VECTOR TO COLD START
	NOP
	JP   WRM	; VECTOR TO WARM START
	DEFB FIGREL	; FIG RELEASE #
	DEFB FIGREV	; FIG REVISION #
	DEFB USRVER	; USER VERSION #
	DEFB 0EH	; IMPLEMENTATION ATTRIBUTES
	DEFW TASK-7	; TOPMOST WORD IN FORTH VOCABULARY
	DEFW BSIN	; BKSPACE CHARACTER
	DEFW INITR0	; INIT (UP)
;<<<<<< FOLLOWING USED BY COLD;
;	MUST BE IN SAME ORDER AS USER VARIABLES
	DEFW INITS0	; INIT (S0)
	DEFW INITR0	; INIT (R0)
	DEFW INITS0	; INIT (TIB)
	DEFW 20H	; INIT (WIDTH)
	DEFW 0	; INIT (WARNING)
	DEFW INITDP	; INIT (FENCE)
	DEFW INITDP	; INIT (DP)
	DEFW FORTH+6	; INIT (VOC-LINK)
;<<<<<< END DATA USED BY COLD
	DEFW 5H,0B320H	; CPU NAME	( HW,LW )
;				  ( 32 BIT, BASE 36 INTEGER )
;
;
;			+---------------+
;	B +ORIGIN	| . . .W:I.E.B.A|	IMPLEMENTATION
;			+---------------+	ATTRIBUTES
;			       ^ ^ ^ ^ ^
;			       | | | | +-- PROCESSOR ADDR =
;			       | | | |     { 0 BYTE | 1 WORD }
;			       | | | +---- HIGH BYTE AT
;			       | | |       { 0 LOW ADDR |
;			       | | |	     1 HIGH ADDR }
;			       | | +------ ADDR MUST BE EVEN
;			       | |	   { 0 YES | 1 NO }
;			       | +-------- INTERPRETER IS
;			       |	   { 0 PRE | 1 POST }
;			       |	   INCREMENTING
;			       +---------- { 0 ABOVE SUFFICIENT
;					     | 1 OTHER DIFFER-
;					     ENCES EXIST }
;
; PAGE
;
;------------------------------------------------------
;
;	FORTH REGISTERS
;
;	FORTH	8080	FORTH PRESERVATION RULES
;	-----	----	------------------------------------------------------------------------HH+	;	IP	BC	SHOULD BE PRESERVED ACROSS
;			  FORTH WORDS
;	W	DE	SOMETIMES OUTPUT FROM NEXT
;			MAY BE ALTERED BEFORE JMP'ING TO NEXT
;			INPUT ONLY WHEN 'DPUSH' CALLED
;	SP	SP	SHOULD BE USED ONLY AS DATA STACK
;			  ACROSS FORTH WORDS
;			MAY BE USED WITHIN FORTH WORDS
;			  IF RESTORED BEFORE 'NEXT'
;		HL	NEVER OUTPUT FROM NEXT
;			INPUT ONLY WHEN 'HPUSH' CALLED
;
UP:	DEFW INITR0	; USER AREA POINTER
RPP:	DEFW INITR0	; RETURN STACK POINTER
;
;------------------------------------------------------
;
;	COMMENT CONVENTIONS:
;
;	=	MEANS	"IS EQUAL TO"
;	<-	MEANS	ASSIGNMENT
;
;	NAME	=	ADDRESS OF NAME
;	(NAME)	=	CONTENTS AT NAME
;	((NAME))=	INDIRECT CONTENTS
;
;	CFA	=	ADDRESS OF CODE FIELD
;	LFA	=	ADDRESS OF LINK FIELD
;	NFA	=	ADDR OF START OF NAME FIELD
;	PFA	=	ADDR OF START OF PARAMETER FIELD
;
;	S1	=	ADDR OF 1ST WORD OF PARAMETER STACK
;	S2	=	ADDR OF 2ND WORD OF PARAMETER STACK
;	R1	=	ADDR OF 1ST WORD OF RETURN STACK
;	R2	=	ADDR OF 2ND WORD OF RETURN STACK
;	( ABOVE STACK POSITIONS VALID BEFORE & AFTER EXECUTION
;	OF ANY WORD, NOT DURING. )
;
;	LSB	=	LEAST SIGNIFICANT BIT
;	MSB	=	MOST SIGNIFICANT BIT
;	LB	=	LOW BYTE
;	HB	=	HIGH BYTE
;	LW	=	LOW WORD
;	HW	=	HIGH WORD
;	( MAY BE USED AS SUFFIX TO ABOVE NAMES )
;
; PAGE
;
;---------------------------------------------------
;	DEBUG SUPPORT
;
;	TO USE:
;	(1)	SET 'BIP' TO IP VALUE TO HALT, CANNOT BE CFA
;	(2)	SET MONITOR'S BREAKPOINT PC TO 'BREAK'
;			OR PATCH 'HLT' INSTR. THERE
;	(3)	PATCH A 'JMP TNEXT' AT 'NEXT'
;	WHEN (IP) = (BIP) CPU WILL HALT
;
BIP:	DEFW 0	; BREAKPOINT ON IP VALUE
;
TNEXT:	LD   HL, BIP
	LD   A, (HL)	; LB
	CP   C
	JP   NZ, TNEXT1
	INC  HL
	LD   A, (HL)	; HB
	CP   B
	JP   NZ, TNEXT1
BREAK:	NOP	; PLACE BREAKPOINT HERE
	NOP
	NOP
TNEXT1:	LD   A, (BC)
	INC  BC
	LD   L, A
	JP   NEXT+3
;
;--------------------------------------------------
;
;	NEXT, THE FORTH ADDRESS INTERPRETER
;	  ( POST INCREMENTING VERSION )
;
DPUSH:	PUSH DE
HPUSH:	PUSH HL
NEXT:	LD   A, (BC)	;(W) <- ((IP))
	INC  BC	;(IP) <- (IP)+2
	LD   L, A
	LD   A, (BC)
	INC  BC
	LD   H, A	; (HL) <- CFA
NEXT1:	LD   E, (HL)	;(PC) <- ((W))
	INC  HL
	LD   D, (HL)
	EX   DE, HL
	JP   (HL)	; NOTE: (DE) = CFA+1
;
; PAGE
;
;		FORTH DICTIONARY
;
;
;	DICTIONARY FORMAT:
;
;				BYTE
;	ADDRESS	NAME		CONTENTS
;	------- ----		--------
;					  ( MSB=1
;					  ( P=PRECEDENCE BIT
;					  ( S=SMUDGE BIT
;	NFA	NAME FIELD	1PS<LEN>  < NAME LENGTH
;				0<1CHAR>  MSB=0, NAME'S 1ST CHAR
;				0<2CHAR>
;				  ...
;				1<LCHAR>  MSB=1, NAME'S LAST CHR
;	LFA	LINK FIELD	<LINKLB>  = PREVIOUS WORD'S NFA
;				<LINKHB>
;LABEL:	CFA	CODE FIELD	<CODELB>  = ADDR CPU CODE
;				<CODEHB>
;	PFA	PARAMETER	<1PARAM>  1ST PARAMETER BYTE
;		FIELD		<2PARAM>
;				  ...
;
;
DP0:	DEFB 83H	; LIT
	DEFB "LI"
	DEFB 'T'+80H
	DEFW 0	; (LFA)=0 MARKS END OF DICTIONARY
LIT:	DEFW $+2	;(S1) <- ((IP))
	LD   A, (BC)	; (HL) <- ((IP)) = LITERAL
	INC  BC	; (IP) <- (IP) + 2
	LD   L, A	; LB
	LD   A, (BC)	; HB
	INC  BC
	LD   H, A
	JP   HPUSH	; (S1) <- (HL)
 ;
	DEFB 87H	; EXECUTE
	DEFB "EXECUT"
	DEFB 'E'+80H
	DEFW LIT-6
EXEC:	DEFW $+2
	POP  HL	; (HL) <- (S1) = CFA
	JP   NEXT1
;
	DEFB 86H	; BRANCH
	DEFB "BRANC"
	DEFB 'H'+80H
	DEFW EXEC-0AH
BRAN:	DEFW $+2	;(IP) <- (IP) + ((IP))
BRAN1:	LD   H, B	; (HL) <- (IP)
	LD   L, C
	LD   E, (HL)	; (DE) <- ((IP)) = BRANCH OFFSET
	INC  HL
	LD   D, (HL)
	DEC  HL
	ADD  HL, DE	; (HL) <- (HL) + ((IP))
	LD   C, L	; (IP) <- (HL)
	LD   B, H
	JP   NEXT
;
	DEFB 87H	; 0BRANCH
	DEFB "0BRANC"
	DEFB 'H'+80H
	DEFW BRAN-9
ZBRAN:	DEFW $+2
	POP  HL
	LD   A, L
	OR   H
	JP   Z, BRAN1	; IF (S1)=0 THEN BRANCH
	INC  BC	; ELSE SKIP BRANCH OFFSET
	INC  BC
	JP   NEXT
;
	DEFB 86H	; (LOOP)
	DEFB "(LOOP"
	DEFB ')'+80H
	DEFW ZBRAN-0AH
XLOOP:	DEFW $+2
	LD   DE, 1	; (DE) <- INCREMENT
XLOO1:	LD   HL, (RPP)	; ((HL)) = INDEX
	LD   A, (HL)	; INDEX <- INDEX + INCR
	ADD  A, E
	LD   (HL), A
	LD   E, A
	INC  HL
	LD   A, (HL)
	ADC  A, D
	LD   (HL), A
	INC  HL	; ((HL)) = LIMIT
	INC  D
	DEC  D
	LD   D, A	; (DE) <- NEW INDEX
	JP   M, XLOO2	; IF INCR > 0
	LD   A, E
	SUB  (HL)	; THEN (A) <- INDEX - LIMIT
	LD   A, D
	INC  HL
	SBC  A, (HL)
	JP   XLOO3
XLOO2:	LD   A, (HL)	; ELSE (A) <- LIMIT - INDEX
	SUB  E
	INC  HL
	LD   A, (HL)
	SBC  A, D
;			; IF (A) < 0
XLOO3:	JP   M, BRAN1	; THEN LOOP AGAIN
	INC  HL	; ELSE DONE
	LD   (RPP), HL	; DISCARD R1 & R2
	INC  BC	; SKIP BRANCH OFFSET
	INC  BC
	JP   NEXT
;
	DEFB 87H	; (+LOOP)
	DEFB "(+LOOP"
	DEFB ')'+80H
	DEFW XLOOP-9
XPLOO:	DEFW $+2
	POP  DE	; (DE) <- INCR
	JP   XLOO1
;
	DEFB 84H	; (DO)
	DEFB "(DO"
	DEFB ')'+80H
	DEFW XPLOO-0AH
XDO:	DEFW $+2
	LD   HL, (RPP)	; (RP) <- (RP) - 4
	DEC  HL
	DEC  HL
	DEC  HL
	DEC  HL
	LD   (RPP), HL
	POP  DE	; (R1) <- (S1) = INIT INDEX
	LD   (HL), E
	INC  HL
	LD   (HL), D
	POP  DE	; (R2) <- (S2) = LIMIT
	INC  HL
	LD   (HL), E
	INC  HL
	LD   (HL), D
	JP   NEXT
;
	DEFB 81H	; I
	DEFB 'I'+80H
	DEFW XDO-7
IDO:	DEFW $+2	;(S1) <- (R1) , (R1) UNCHANGED
	LD   HL, (RPP)
	LD   E, (HL)	; (DE) <- (R1)
	INC  HL
	LD   D, (HL)
	PUSH DE	; (S1) <- (DE)
	JP   NEXT
;
	DEFB 85H	; DIGIT
	DEFB "DIGI"
	DEFB 'T'+80H
	DEFW IDO-4
DIGIT:	DEFW $+2
	POP  HL	; (L) <- (S1)LB = ASCII CHR TO BE
;			 CONVERTED
	POP  DE	; (DE) <- (S2) = BASE VALUE
	LD   A, E
	SUB  30H	; IF CHR > "0"
	JP   M, DIGI2
	CP   0AH	; AND IF CHR > "9"
	JP   M, DIGI1
	SUB  7
	CP   0AH	; AND IF CHR >= "A"
	JP   M, DIGI2
;			; THEN VALID NUMERIC OR ALPHA CHR
DIGI1:	CP   L	; IF < BASE VALUE
	JP   P, DIGI2
;			; THEN VALID DIGIT CHR
	LD   E, A	; (S2) <- (DE) = CONVERTED DIGIT
	LD   HL, 1	; (S1) <- TRUE
	JP   DPUSH
;			; ELSE INVALID DIGIT CHR
DIGI2:	LD   L, H	; (HL) <- FALSE
	JP   HPUSH	; (S1) <- FALSE
;
	DEFB 86H	; (FIND)  (2-1)FAILURE
	DEFB "(FIND"	; (2-3)SUCCESS
	DEFB ')'+80H
	DEFW DIGIT-8
PFIND:	DEFW $+2
	POP  DE	; (DE) <- NFA
PFIN1:	POP  HL	; (HL) <- STRING ADDR
	PUSH HL	; SAVE STRING ADDR FOR NEXT ITERATION
	LD   A, (DE)
	XOR  (HL)	; CHECK LENGTHS & SMUDGE BIT
	AND  3FH
	JP   NZ, PFIN4	; LENGTHS DIFFERENT
;			; LENGTHS MATCH, CHECK EACH CHR
PFIN2:	INC  HL	; (HL) <- ADDR NEXT CHR IN STRING
	INC  DE	; (DE) <- ADDR NEXT CHR IN NF
	LD   A, (DE)
	XOR  (HL)	; IGNORE MSB
	ADD  A, A
	JP   NZ, PFIN3	; NO MATCH
	JP   NC, PFIN2	; MATCH SO FAR, LOOP AGAIN
	LD   HL, 5	; STRING MATCHES
	ADD  HL, DE	; ((SP)) <- PFA
	EX   (SP), HL
;			; BACK UP TO LENGTH BYTE OF NF = NFA
PFIN6:	DEC  DE
	LD   A, (DE)
	OR   A
	JP   P, PFIN6	; IF MSB = 1 THEN (DE) = NFA
	LD   E, A	; (DE) <- LENGTH BYTE
	LD   D, 0
	LD   HL, 1	; (HL) <- TRUE
	JP   DPUSH	; RETURN, NF FOUND
;	ABOVE NF NOT A MATCH, TRY ANOTHER
PFIN3:	JP   C, PFIN5	; IF NOT END OF NF
PFIN4:	INC  DE	; THEN FIND END OF NF
	LD   A, (DE)
	OR   A
	JP   P, PFIN4
PFIN5:	INC  DE	; (DE) <- LFA
	EX   DE, HL
	LD   E, (HL)	; (DE) <- (LFA)
	INC  HL
	LD   D, (HL)
	LD   A, D
	OR   E	; IF (LFA) <> 0
	JP   NZ, PFIN1	; THEN TRY PREVIOUS DICT. DEF.
;			; ELSE END OF DICTIONARY
	POP  HL	; DISCARD STRING ADDR
	LD   HL, 0	; (HL) <- FALSE
	JP   HPUSH	; RETURN, NO MATCH FOUND
;
	DEFB 87H	; ENCLOSE
	DEFB "ENCLOS"
	DEFB 'E'+80H
	DEFW PFIND-9
ENCL:	DEFW $+2
	POP  DE	; (DE) <- (S1) = DELIMITER CHAR
	POP  HL	; (HL) <- (S2) = ADDR TEXT TO SCAN
	PUSH HL	; (S4) <- ADDR
	LD   A, E
	LD   D, A	; (D) <- DELIM CHR
	LD   E, -1	; INITIALIZE CHR OFFSET COUNTER
	DEC  HL	; (HL) <- ADDR-1
;			; SKIP OVER LEADING DELIMITER CHRS
ENCL1:	INC  HL
	INC  E
	CP   (HL)	; IF TEXT CHR = DELIM CHR
	JP   Z, ENCL1	; THEN LOOP AGAIN
;			; ELSE NON-DELIM CHR FOUND
	LD   D, 0	; (S3) <- (E) = OFFSET TO 1ST NON-DELIM
	PUSH DE
	LD   D, A	; (D) <- DELIM CHR
	LD   A, (HL)	; IF 1ST NON-DELIM = NULL
	AND  A
	JP   NZ, ENCL2
	LD   D, 0	; THEN (S2) <- OFFSET TO BYTE
	INC  E	;   FOLLOWING NULL
	PUSH DE
	DEC  E	; (S1) <- OFFSET TO NULL
	PUSH DE
	JP   NEXT
;			; ELSE TEXT CONTAINS NON-DELIM &
;			  NON-NULL CHR
ENCL2:	LD   A, D	; (A) <- DELIM CHR
	INC  HL	; (HL) <- ADDR NEXT CHR
	INC  E	; (E) <- OFFSET TO NEXT CHR
	CP   (HL)	; IF NEXT CHR <> DELIM CHR
	JP   Z, ENCL4
	LD   A, (HL)	; AND IF NEXT CHR <> NULL
	AND  A
	JP   NZ, ENCL2	; THEN CONTINUE SCAN
;			; ELSE CHR = NULL
ENCL3:	LD   D, 0	; (S2) <- OFFSET TO NULL
	PUSH DE
	PUSH DE	; (S1) <- OFFSET TO NULL
	JP   NEXT
;			; ELSE CHR = DELIM CHR
ENCL4:	LD   D, 0	; (S2) <- OFFSET TO BYTE
;			  FOLLOWING TEXT
	PUSH DE
	INC  E	; (S1) <- OFFSET TO 2 BYTES AFTER
;			    END OF WORD
	PUSH DE
	JP   NEXT
;
	DEFB 84H	; EMIT
	DEFB "EMI"
	DEFB 'T'+80H
	DEFW ENCL-0AH
EMIT:	DEFW DOCOL
	DEFW PEMIT
	DEFW ONE,OUTT
	DEFW PSTOR,SEMIS
;
	DEFB 83H	; KEY
	DEFB "KE"
	DEFB 'Y'+80H
	DEFW EMIT-7
KEY:	DEFW $+2
	JP   PKEY
;
	DEFB 89H	; ?TERMINAL
	DEFB "?TERMINA"
	DEFB 'L'+80H
	DEFW KEY-6
QTERM:	DEFW $+2
	LD   HL, 0
	JP   PQTER
;
	DEFB 82H	; CR
	DEFB 'C'
	DEFB 'R'+80H
	DEFW QTERM-0CH
CR:	DEFW $+2
	JP   PCR
;
	DEFB 85H	; CMOVE
	DEFB "CMOV"
	DEFB 'E'+80H
	DEFW CR-5
CMOVE:	DEFW $+2
	LD   L, C	; (HL) <- (IP)
	LD   H, B
	POP  BC	; (BC) <- (S1) = #CHRS
	POP  DE	; (DE) <- (S2) = DEST ADDR
	EX   (SP), HL	; (HL) <- (S3) = SOURCE ADDR
;			; (S1) <- (IP)
	JP   CMOV2	; RETURN IF #CHRS = 0
CMOV1:	LD   A, (HL)	; ((DE)) <- ((HL))
	INC  HL	; INC SOURCE ADDR
	LD   (DE), A
	INC  DE	; INC DEST ADDR
	DEC  BC	; DEC #CHRS
CMOV2:	LD   A, B
	OR   C
	JP   NZ, CMOV1	; REPEAT IF #CHRS <> 0
	POP  BC	; RESTORE (IP) FROM (S1)
	JP   NEXT
;
	DEFB 82H	; U*	16X16 UNSIGNED MULTIPLY
	DEFB 'U'	; AVG EXECUUION TIME = 994 CYCLES
	DEFB '*'+80H
	DEFW CMOVE-8
USTAR:	DEFW $+2
	POP  DE	; (DE) <- MPLIER
	POP  HL	; (HL) <- MPCAND
	PUSH BC	; SAVE IP
	LD   B, H
	LD   A, L	; (BA) <- MPCAND
	CALL MPYX	; (AHL)1 <- MPCAND.LB * MPLIER
;			       1ST PARTIAL PRODUCT
	PUSH HL	; SAVE (HL)1
	LD   H, A
	LD   A, B
	LD   B, H	; SAVE (A)1
	CALL MPYX	; (AHL)2 <- MPCAND.HB * MPLIER
;			       2ND PARTIAL PRODUCT
	POP  DE	; (DE) <- (HL)1
	LD   C, D	; (BC) <- (AH)1
;	FORM SUM OF PARTIALS:
;			   (AHL) 1
;			+ (AHL)  2
;			--------
;			  (AHLE)
	ADD  HL, BC	; (HL) <- (HL)2 + (AH)1
	ADC  A, 0	; (AHLE) <- (BA) * (DE)
	LD   D, L
	LD   L, H
	LD   H, A	; (HLDE) <- MPLIER * MPCAND
	POP  BC	; RESTORE IP
	PUSH DE	; (S2) <- PRODUCT.LW
	JP   HPUSH	; (S1) <- PRODUCT.HW
;
;	MULTIPLY PRIMITIVE
;		(AHL) <- (A) * (DE)
;	#BITS =	 24	  8	16
MPYX:	LD   HL, 0	; (HL) <- 0 = PARTIAL PRODUCT.LW
	LD   C, 8	; LOOP COUNTER
MPYX1:	ADD  HL, HL	; LEFT SHIFT (AHL) 24 BITS
	RLA
	JP   NC, MPYX2	; IF NEXT MPLIER BIT = 1
	ADD  HL, DE	; THEN ADD MPCAND
	ADC  A, 0
MPYX2:	DEC  C	; IF NOT LAST MPLIER BIT
	JP   NZ, MPYX1	; THEN LOOP AGAIN
	RET	; ELSE DONE
;
	DEFB 82H	; U/
	DEFB 'U'
	DEFB '/'+80H
	DEFW USTAR-5
USLAS:	DEFW $+2
	LD   HL, 4
	ADD  HL, SP	; ((HL)) <- NUMERATOR.LW
	LD   E, (HL)	; (DE) <- NUMER.LW
	LD   (HL), C	; SAVE IP ON STACK
	INC  HL
	LD   D, (HL)
	LD   (HL), B
	POP  BC	; (BC) <- DENOMINATOR
	POP  HL	; (HL) <- NUMER.HW
	LD   A, L
	SUB  C	; IF NUMER >= DENOM
	LD   A, H
	SBC  A, B
	JP   C, USLA1
	LD   HL, 0FFFFH	; THEN OVERFLOW
	LD   DE, 0FFFFH	; SET REM & QUOT TO MAX
	JP   USLA7
USLA1:	LD   A, 16	; LOOP COUNTER
USLA2:	ADD  HL, HL	; LEFT SHIFT (HLDE) THRU CARRY
	RLA
	EX   DE, HL
	ADD  HL, HL
	JP   NC, USLA3
	INC  DE
	AND  A
USLA3:	EX   DE, HL	; SHIFT DONE
	RRA	; RESTORE 1ST CARRY
	PUSH AF	; SAVE COUNTER
	JP   NC, USLA4	; IF CARRY = 1
	LD   A, L	; THEN (HL) <- (HL) - (BC)
	SUB  C
	LD   L, A
	LD   A, H
	SBC  A, B
	LD   H, A
	JP   USLA5
USLA4:	LD   A, L	; ELSE TRY (HL) <- (HL) - (BC)
	SUB  C
	LD   L, A
	LD   A, H
	SBC  A, B	; (HL) <- PARTIAL REMAINDER
	LD   H, A
	JP   NC, USLA5
	ADD  HL, BC	; UNDERFLOW, RESTORE
	DEC  DE
USLA5:	INC  DE	; INC QUOT
USLA6:	POP  AF	; RESTORE COUNTER
	DEC  A	; IF COUNTER > 0
	JP   NZ, USLA2	; THEN LOOP AGAIN
USLA7:	POP  BC	; ELSE DONE, RESTORE IP
	PUSH HL	; (S2) <- REMAINDER
	PUSH DE	; (S1) <- QUOTIENT
	JP   NEXT
;
	DEFB 83H	; AND
	DEFB "AN"
	DEFB 'D'+80H
	DEFW USLAS-5
ANDD:	DEFW $+2	; (S1) <- (S1) AND (S2)
	POP  DE
	POP  HL
	LD   A, E
	AND  L
	LD   L, A
	LD   A, D
	AND  H
	LD   H, A
	JP   HPUSH
;
	DEFB 82H	; OR
	DEFB 'O'
	DEFB 'V'+80H
	DEFW ANDD-6
ORR:	DEFW $+2	; (S1) <- (S1) OR (S2)
