	POP  HL	; (HL) <- (S2) = X
	LD   A, D	; IF X & Y HAVE SAME SIGNS
	XOR  H
	JP   M, LES1
	CALL SSUB	; (HL) <- X - Y
LES1:	INC  H	; IF (HL) >= 0
	DEC  H
	JP   M, LES2
	LD   HL, 0	; THEN X >= Y
	JP   HPUSH	; (S1) <- FALSE
LES2:	LD   HL, 1	; ELSE X < Y
	JP   HPUSH	; (S1) <- TRUE
