; PAGE
;--------------------------------------------------
;	BLOCK STUB (no disk I/O on NostOS)
;
; BLOCK is needed by WORD and (LINE) at assembly time.
; Since NostOS has no disk screens, BLOCK returns a
; pointer to a static empty buffer. This path is only
; taken when BLK is non-zero (loading from screen).
;
BLOCK:	DEFW	DOCOL
	DEFW	DROP
	DEFW	LIT
	DEFW	forth_block_buf
	DEFW	SEMIS
;
;
; PAGE
;--------------------------------------------------
;	NostOS CONSOLE INTERFACE
;
EPRINT:	DEFW	0	; ENABLE PRINTER VARIABLE
;			; 0 = DISABLED, 1 = ENABLED
;
; NostOS does not have a non-blocking console status check,
; so ?TERMINAL always returns false. This means you cannot
; interrupt long listings with a keypress.
;
CSTAT:	XOR	A	; CONSOLE STATUS: always 0 (no char)
	RET
;
CIN:	PUSH	BC	; CONSOLE INPUT
	LD	B, LOGDEV_ID_CONI
	LD	C, DEV_CREAD_RAW
	CALL	KERNELADDR	; L = char read
	LD	A, L
	POP	BC
	RET
;
COUT:	PUSH	HL	; CONSOLE OUTPUT char in C
	PUSH	BC
	LD	E, C		; E = char to write
	LD	B, LOGDEV_ID_CONO
	LD	C, DEV_CWRITE
	CALL	KERNELADDR
	POP	BC
	POP	HL
	RET
;
; No printer support on NostOS - POUT is a no-op
POUT:	RET
;
CPOUT:	CALL	COUT	; OUTPUT (C) TO CONSOLE
	EX	DE, HL
	LD	HL, EPRINT
	LD	A, (HL)
	OR	A
	JP	Z, CPOU1
	LD	C, E
	CALL	POUT
CPOU1:	RET
;
;	FORTH TO NostOS SERIAL IO INTERFACE
;
PQTER:	CALL	CSTAT	; IF CHR TYPED
	LD	HL, 0
	OR	A
	JP	Z, PQTE1
	INC	L	; THEN (S1) <- TRUE
PQTE1:	JP	HPUSH	; ELSE (S1) <- FALSE
;
PKEY:	CALL	CIN	; READ CHR FROM CONSOLE
	CP	DLE	; IF CHR = (^P)
	LD	E, A
	JP	NZ, PKEY1
	LD	HL, EPRINT	; THEN TOGGLE (EPRINT)LSB
	LD	E, ABL	; CHR <- BLANK
	LD	A, (HL)
	XOR	1
	LD	(HL), A
PKEY1:	LD	L, E
	LD	H, 0
	JP	HPUSH	; (S1)LB <- CHR
;
PEMIT:	DEFW	$+2	; (EMIT)	ORPHAN
	POP	HL	; (L) <- (S1)LB = CHR
	LD	A, L
	AND	7FH	; STRIP HIGH BIT (FIG-FORTH STANDARD)
	LD	L, A
	PUSH	BC	; SAVE (IP)
	LD	C, L
	CALL	CPOUT	; OUTPUT CHR TO CONSOLE
;			; & MAYBE PRINTER
	POP	BC	; RESTORE (IP)
	JP	NEXT
;
PCR:	PUSH	BC	; SAVE (IP)
	LD	C, ACR	; OUTPUT (CR) TO CONSOLE
	LD	L, C
	CALL	CPOUT	; & MAYBE TO PRINTER
	LD	C, LF	; OUTPUT (LF) TO CONSOLE
	LD	L, C
	CALL	CPOUT	; & MAYBE TO PRINTER
	POP	BC	; RESTORE (IP)
	JP	NEXT
;
