	DEFB "BY"
	DEFB 'E'+80H
	DEFW VLIST-8
BYE:	DEFW $+2
	LD   C, SYS_EXIT
	CALL KERNELADDR
;-----------------------------------------------
;
	DEFB 84H	; LIST
	DEFB "LIS"
	DEFB 'T'+80H
	DEFW BYE-6
LIST:	DEFW DOCOL,DEC
	DEFW CR,DUP
	DEFW SCR,STORE
	DEFW PDOTQ
	DEFB 6,"SCR # "
	DEFW DOT
	DEFW LIT,10H
	DEFW ZERO,XDO
LIST1:	DEFW CR,IDO
	DEFW LIT,3
	DEFW DOTR,SPACE
	DEFW IDO,SCR
	DEFW AT,DLINE
	DEFW QTERM	; ?TERMINAL
	DEFW ZBRAN
	DEFW LIST2-$	; IF
	DEFW LEAVE	; LEAVE
LIST2:	DEFW XLOOP
	DEFW LIST1-$	; ENDIF
	DEFW CR,SEMIS
;
	DEFB 85H	; INDEX
	DEFB "INDE"
	DEFB 'X'+80H
	DEFW LIST-7
INDEX:	DEFW DOCOL
	DEFW LIT,FF
	DEFW EMIT,CR
	DEFW ONEP,SWAP
	DEFW XDO
INDE1:	DEFW CR,IDO
	DEFW LIT,3
	DEFW DOTR,SPACE
	DEFW ZERO,IDO
	DEFW DLINE,QTERM
	DEFW ZBRAN
	DEFW INDE2-$
	DEFW LEAVE
INDE2:	DEFW XLOOP
	DEFW INDE1-$
	DEFW SEMIS
;
	DEFB 85H	; TRIAD
	DEFB "TRIA"
	DEFB 'D'+80H
	DEFW INDEX-8
TRIAD:	DEFW DOCOL
	DEFW LIT,FF
	DEFW EMIT
	DEFW LIT,3
	DEFW SLASH
	DEFW LIT,3
	DEFW STAR
	DEFW LIT,3
	DEFW OVER,PLUS
	DEFW SWAP,XDO
TRIA1:	DEFW CR,IDO
	DEFW LIST
	DEFW QTERM	; ?TERMINAL
	DEFW ZBRAN
	DEFW TRIA2-$	; IF
	DEFW LEAVE	; LEAVE
TRIA2:	DEFW XLOOP
	DEFW TRIA1-$	; ENDIF
	DEFW CR
	DEFW LIT,15
	DEFW MESS,CR
	DEFW SEMIS
;
	DEFB 84H	; .CPU
	DEFB ".CP"
	DEFB 'U'+80H
	DEFW TRIAD-8
DOTCPU:	DEFW DOCOL
	DEFW BASE,AT
	DEFW LIT,36
	DEFW BASE,STORE
	DEFW LIT,22H
	DEFW PORIG,TAT
	DEFW DDOT
	DEFW BASE,STORE
	DEFW SEMIS
;
	DEFB 84H	; TASK
	DEFB "TAS"
	DEFB 'K'+80H
	DEFW DOTCPU-7
TASK:	DEFW DOCOL
	DEFW SEMIS
;
;
; Static buffer for BLOCK stub (128 bytes)
forth_block_buf:
	DEFS	128, 0
;
INITDP:			;END OF INITIAL DICTIONARY
;
; PAGE
;
;		MEMORY MAP
;	( THE FOLLOWING EQUATES ARE NOT REFERENCED ELSEWHERE )
;
;		LOCATION	CONTENTS
;		--------	--------
MCOLD:	EQU ORIG	;JMP TO COLD START
MWARM:	EQU ORIG+4	;JMP TO WARM START
MA2:	EQU ORIG+8	;COLD START PARAMETERS
MUP:	EQU UP	;USER VARIABLES' BASE 'REG'
MRP:	EQU RPP	;RETURN STACK 'REGISTER'
;
MBIP:	EQU BIP	;DEBUG SUPPORT
MDPUSH:	EQU DPUSH	;ADDRESS INTERPRETER
MHPUSH:	EQU HPUSH
MNEXT:	EQU NEXT
;
MDP0:	EQU DP0	;START FORTH DICTIONARY
; MDIO	EQU DRIVE	;CP/M DISK INTERFACE
MCIO:	EQU EPRINT	;CONSOLE & PRINTER INTERFACE
MIDP:	EQU INITDP	;END INITIAL FORTH DICTIONARY
;				  = COLD (DP) VALUE
;				  = COLD (FENCE) VALUE
;				  |  NEW
;				  |  DEFINITIONS
;				  V
;
;				  ^
;				  |  DATA
;				  |  STACK
MIS0:	EQU INITS0	;  = COLD (SP) VALUE = (S0)
;				   = (TIB)
;				  |  TERMINAL INPUT
;				  |  BUFFER
;				  V
;
;				  ^
;				  |  RETURN
;				  |  STACK
MIR0:	EQU INITR0	;START USER VARIABLES
;				  = COLD (RP) VALUE = (R0)
;				  = (UP)
;				;END USER VARIABLES
; MFIRST	EQU BUF1	;START DISK BUFFERS
;				  = FIRST
MEND:	EQU EM-1	;END DISK BUFFERS
MLIMIT:	EQU EM	;LAST MEMORY LOC USED + 1
;				  = LIMIT
;
;
; END
